// TypeScript: Detect stuck state
class StuckDetector {
  private lastScreenshot: string = '';
  private unchangedCount: number = 0;
  private stuckThreshold: number = 15; // 15 seconds

  detectStuck(currentScreenshot: string): boolean {
    // Check if screenshot hasn't changed
    if (currentScreenshot === this.lastScreenshot) {
      this.unchangedCount++;

      // Stuck after threshold
      if (this.unchangedCount >= this.stuckThreshold) {
        return true;
      }
    } else {
      this.unchangedCount = 0; // Reset on change
    }

    this.lastScreenshot = currentScreenshot;
    return false;
  }
}

// Detect repeated actions
class LoopDetector {
  private actionHistory: string[] = [];
  private loopThreshold: number = 3; // 3 repeated actions

  detectLoop(action: string): boolean {
    // Track recent actions
    this.actionHistory.push(action);

    // Keep only last N actions
    if (this.actionHistory.length > 10) {
      this.actionHistory = this.actionHistory.slice(-10);
    }

    // Check for repeated pattern
    const recentActions = this.actionHistory.slice(-this.loopThreshold);
    const allSame = recentActions.every(a => a === action);

    return allSame;
  }
}

# Python: Retry with exponential backoff
def retry_with_backoff(action, max_retries=3):
    """Retry action with exponential backoff"""

    for attempt in range(max_retries):
        try:
            result = action()
            return result  # Success
        except Exception as e:
            if attempt == max_retries - 1:
                raise  # Last attempt, fail

            # Exponential backoff: 1s, 2s, 4s, ...
            sleep_time = 2 ** attempt
            print(f"Attempt {attempt + 1} failed, retrying in {sleep_time}s")
            time.sleep(sleep_time)

# Python: Circuit breaker for agent failures
class CircuitBreaker:
    def __init__(self, failure_threshold=5, timeout=30):
        self.failure_count = 0
        self.failure_threshold = failure_threshold
        self.timeout = timeout
        self.state = "CLOSED"  # CLOSED, OPEN, HALF_OPEN
        self.last_failure_time = None

    def call(self, agent_action):
        if self.state == "OPEN":
            # Check if timeout passed
            if time.time() - self.last_failure_time > self.timeout:
                self.state = "HALF_OPEN"
            else:
                raise Exception("Circuit breaker open")

        try:
            result = agent_action()
            self.success()
            return result
        except Exception as e:
            self.failure()
            raise e

    def success(self):
        self.failure_count = 0
        self.state = "CLOSED"

    def failure(self):
        self.failure_count += 1
        self.last_failure_time = time.time()

        if self.failure_count >= self.failure_threshold:
            self.state = "OPEN"

// TypeScript: Detect stuck from terminal output
class StatusDetector {
  private lastContent: string = '';
  private unchangedCount: number = 0;
  private stuckThreshold: number = 15;

  detectStatus(content: string): ClaudeStatus {
    // Check for no state change
    if (content === this.lastContent) {
      this.unchangedCount++;

      if (this.unchangedCount >= this.stuckThreshold) {
        return {
          primary: 'stuck',
          detail: null,
          health: 'STUCK',
          timestamp: new Date().toISOString(),
          unchangedCount: this.unchangedCount
        };
      }
    } else {
      this.unchangedCount = 0;
    }

    this.lastContent = content;
    return this.analyzeContent(content);
  }
}

