def detect_stuck_patterns(screenshot):
    """Detect visual patterns indicating stuck state"""

    # Pattern 1: Same UI element highlighted repeatedly
    highlighted_elements = find_highlighted_elements(screenshot)
    if len(highlighted_elements) == 1 and highlighted_elements[0] == last_highlighted:
        return "stuck_highlighting_same_element"

    # Pattern 2: Error message on screen
