# Python: Escalate to human when stuck
def escalate_to_human(agent, task_context, stuck_reason):
    """Escalate to human when agent cannot recover"""

    # Notify human operator
    send_notification(
        channel="slack",
        message=f"Agent stuck: {stuck_reason}\nTask: {task_context}\n"
                f"Last action: {agent.last_action}\nScreenshot: {agent.last_screenshot}"
    )

    # Wait for human input
    human_decision = wait_for_human_input(timeout=300)

    if human_decision == "retry_with_different_approach":
        return recover_with_different_approach(agent)
    elif human_decision == "cancel_task":
        return cancel_task(agent)
    elif human_decision == "fix_manual":
        return manual_intervention(agent)
